mepc_setup:       
                  la x12, init
                  csrw 0x341, x12

custom_csr_setup: 
                  csrwi 0x7c0, 1

init_machine_mode:
                  li x12, 0x448018f6
                  csrw 0x300, x12 # MSTATUS
                  li x12, 0xa8ca3bbf
                  csrw 0x304, x12 # MIE
                  li x22, 0x8ffffffc
